#!/usr/bin/env node

import { readFile, writeFile } from "node:fs/promises";
import { resolve } from "node:path";
import { fileURLToPath } from "node:url";

import { API_DECLARATIONS } from "../sdk/api-surface-model.mjs";
import { listBuiltinJobSchemas } from "../mcp-server/src/core/job-schema-registry.js";

const repoRoot = resolve(fileURLToPath(new URL("..", import.meta.url)));
const outPath = resolve(repoRoot, "sdk/agent-platform-client.d.ts");
const CHECK = process.argv.includes("--check");

const header = `/**
 * Generated by scripts/generate-sdk-types.mjs.
 * Sources:
 * - sdk/api-surface-model.mjs
 * - mcp-server/src/core/job-schema-registry.js
 *
 * Do not edit this file manually. Update the source model or schema registry,
 * then run npm run generate:sdk-types.
 */
`;

const schemaTypes = generateBuiltinSchemaTypes();
const content = `${header}\n${API_DECLARATIONS.replace("{{BUILTIN_JOB_SCHEMA_TYPES}}", schemaTypes).trim()}\n`;

if (CHECK) {
  const current = await readFile(outPath, "utf8");
  if (current !== content) {
    console.error("sdk/agent-platform-client.d.ts is out of date. Run npm run generate:sdk-types.");
    process.exitCode = 1;
  }
} else {
  await writeFile(outPath, content);
}

function generateBuiltinSchemaTypes() {
  const schemas = listBuiltinJobSchemas({ includeDefinitions: true });
  const entries = schemas.map((entry) => {
    const ref = entry.$id;
    const typeName = schemaRefToTypeName(ref);
    return { ...entry, ref, typeName };
  });

  const interfaces = entries.map(({ description, schema, typeName }) => {
    const body = objectPropertiesToTs(schema, 0);
    return [
      description ? `/** ${escapeComment(description)} */` : undefined,
      `export interface ${typeName} ${body}`
    ].filter(Boolean).join("\n");
  });

  const mapEntries = entries.map(({ ref, typeName }) => `  ${JSON.stringify(ref)}: ${typeName};`);

  return [
    interfaces.join("\n\n"),
    "export interface BuiltinJobSchemaMap {",
    ...mapEntries,
    "}",
    "",
    "export type BuiltinJobSchemaRef = keyof BuiltinJobSchemaMap;",
    "export type BuiltinJobSchemaValue<T extends BuiltinJobSchemaRef> = BuiltinJobSchemaMap[T];",
    "export type StructuredSubmission = BuiltinJobSchemaMap[BuiltinJobSchemaRef] | JsonObject;"
  ].join("\n");
}

function schemaRefToTypeName(ref) {
  const name = String(ref).replace(/^schema:\/\/jobs\//u, "");
  return name
    .split(/[^a-z0-9]+/iu)
    .filter(Boolean)
    .map((part) => `${part.slice(0, 1).toUpperCase()}${part.slice(1)}`)
    .join("");
}

function schemaToTs(schema, level) {
  if (!schema || typeof schema !== "object") {
    return "unknown";
  }
  if (Array.isArray(schema.enum) && schema.enum.length) {
    return schema.enum.map((entry) => JSON.stringify(entry)).join(" | ");
  }
  if (schema.type === "string") {
    return "string";
  }
  if (schema.type === "integer" || schema.type === "number") {
    return "number";
  }
  if (schema.type === "boolean") {
    return "boolean";
  }
  if (schema.type === "array") {
    const itemType = schemaToTs(schema.items ?? {}, level);
    return itemType.includes("\n") ? `Array<${itemType}>` : `${itemType}[]`;
  }
  if (schema.type === "object") {
    return objectPropertiesToTs(schema, level);
  }
  return "unknown";
}

function objectPropertiesToTs(schema, level) {
  const indent = "  ".repeat(level);
  const childIndent = "  ".repeat(level + 1);
  const required = new Set(schema.required ?? []);
  const properties = Object.entries(schema.properties ?? {});
  if (!properties.length) {
    return "{ [key: string]: unknown; }";
  }
  const lines = properties.map(([name, propertySchema]) => {
    const optional = required.has(name) ? "" : "?";
    return `${childIndent}${formatPropertyName(name)}${optional}: ${schemaToTs(propertySchema, level + 1)};`;
  });
  return `{\n${lines.join("\n")}\n${indent}}`;
}

function formatPropertyName(name) {
  return /^[A-Za-z_$][A-Za-z0-9_$]*$/u.test(name) ? name : JSON.stringify(name);
}

function escapeComment(value) {
  return String(value).replace(/\*\//gu, "* /");
}
